import('./src/classifier/cadence.js').then(({ classifyCadence }) => {
  // Secondary heuristic concern: could a regular-ish feed with small n
  // trigger rangeRatio > 5 AND jitter > 0.5 incorrectly?
  // E.g., a 'minutes' feed with occasional slightly longer gaps at startup

  // Simulate a mostly-regular 5-min feed with first gap being a bit longer
  const base = 1700000000000;
  const gaps = [600000, 300000, 300000, 300000, 300000, 300000, 300000, 300000]; // 10min first, then 5min
  const events = [{timestamp: base, value: 5, metadata: {}}];
  let t = base;
  for (const g of gaps) { t += g; events.push({timestamp: t, value: 5, metadata: {}}); }
  const p = classifyCadence(events);
  console.log('Mostly-regular 5min with 1 double gap:', p.classification, 
    'jitter:', p.jitter_coefficient?.toFixed(3),
    'rangeRatio: 600000/300000=2');
  // rangeRatio = 600000/300000 = 2 < 5 → won't trigger secondary. Good.

  // What about a feed with one extreme outlier gap?
  // 9 events at 1-min, plus 1 at 10-min → rangeRatio=10, but jitter should be moderate
  const gaps2 = [60000, 60000, 60000, 60000, 60000, 60000, 60000, 60000, 600000]; // 9×1min + 10min
  const events2 = [{timestamp: base, value: 5, metadata: {}}];
  t = base;
  for (const g of gaps2) { t += g; events2.push({timestamp: t, value: 5, metadata: {}}); }
  const p2 = classifyCadence(events2);
  console.log('9×1min + 1×10min feed:', p2.classification,
    'jitter:', p2.jitter_coefficient?.toFixed(3));
