import { ingest } from './src/ingester/generic.js';
import { readFileSync } from 'node:fs';

const usgs = JSON.parse(readFileSync('fixtures/usgs-m4.5-day.json', 'utf8'));
const events = ingest(usgs).sort((a,b) => a.timestamp - b.timestamp);

console.log('=== TREMOR TIMING ANALYSIS ===');
const deltas = [];
for (let i = 1; i < events.length; i++) {
  deltas.push(events[i].timestamp - events[i-1].timestamp);
}
const sorted = [...deltas].sort((a,b)=>a-b);
const n = sorted.length;
const median = sorted[Math.floor(n/2)];
const mean = deltas.reduce((a,b)=>a+b,0)/deltas.length;
const stddev = Math.sqrt(deltas.reduce((s,x)=>s+(x-mean)**2,0)/deltas.length);
const q25 = sorted[Math.floor(n*0.25)];
const q75 = sorted[Math.floor(n*0.75)];
const IQR = q75 - q25;
const fence = q75 + 1.5 * IQR;

console.log('count:', n, 'min:', sorted[0]/1000, 's, max:', sorted[n-1]/1000, 's');
console.log('median:', median/1000, 's, mean:', mean.toFixed(0)/1000, 's');
console.log('stddev:', stddev.toFixed(0)/1000, 's, cv:', (stddev/mean).toFixed(3));
console.log('mean/median:', (mean/median).toFixed(3));
console.log('max/median:', (sorted[n-1]/median).toFixed(3));
console.log('q25:', q25/1000, 's, q75:', q75/1000, 's, IQR:', IQR/1000, 's');
console.log('fence:', fence/1000, 's');
console.log('outliers above fence:', deltas.filter(d => d > fence).length);
console.log('jitter cv:', (stddev/mean).toFixed(3));
console.log('\nAll deltas (s):', deltas.map(d => (d/1000).toFixed(0)).join(', '));

// Now let's look at the actual value distribution differently
// Values are timestamps — check if they're monotonically increasing with spikes
const vals = events.map(e => e.value);
console.log('\n=== VALUE ANALYSIS (are values timestamps?) ===');
console.log('Sample values:', vals.slice(0,5));
console.log('Min value > 1e12?', Math.min(...vals) > 1e12);
console.log('Max value > 1e12?', Math.max(...vals) > 1e12);

// Compute delta of values (how much each value changes from previous)
const valDeltas = [];
const sortedEvents = [...events].sort((a,b) => a.timestamp - b.timestamp);
for (let i = 1; i < sortedEvents.length; i++) {
  valDeltas.push(sortedEvents[i].value - sortedEvents[i-1].value);
}
console.log('Value deltas (ms):', valDeltas.slice(0,5));
const vdMean = valDeltas.reduce((a,b)=>a+b,0)/valDeltas.length;
const vdStd = Math.sqrt(valDeltas.reduce((s,x)=>s+(x-vdMean)**2,0)/valDeltas.length);
console.log('Value delta mean:', vdMean.toFixed(0), 'std:', vdStd.toFixed(0), 'cv:', (vdStd/Math.abs(vdMean)).toFixed(3));
EOF

