import { ingest } from './src/ingester/generic.js';
import { classify } from './src/classifier/feed-grammar.js';
import { anonymize } from './test/convergence/anonymizer.js';
import { readFileSync } from 'node:fs';

const specs = [
  { name: 'TREMOR', expectedNoise: 'spike_driven', expectedDensity: 'sparse_network',
    load: () => JSON.parse(readFileSync('fixtures/usgs-m4.5-day.json', 'utf8')),
    seed: 'tremor' },
  { name: 'CORONA', expectedNoise: 'mixed', expectedDensity: 'single_point',
    load: () => {
      const swpc = JSON.parse(readFileSync('fixtures/swpc-goes-xray.json', 'utf8'));
      const donki = JSON.parse(readFileSync('fixtures/donki-flr-cme.json', 'utf8'));
      return { xray_flux: swpc.xray_flux, kp_index: swpc.kp_index, flares: donki.flares, cmes: donki.cmes };
    },
    seed: 'corona' },
  { name: 'BREATH', expectedNoise: 'mixed', expectedDensity: 'multi_tier',
    load: () => {
      const pa = JSON.parse(readFileSync('fixtures/purpleair-sf-bay.json', 'utf8'));
      const an = JSON.parse(readFileSync('fixtures/airnow-sf-bay.json', 'utf8'));
      return { purpleair: pa, airnow: an };
    },
    seed: 'breath' },
];

for (const spec of specs) {
  const raw = spec.load();

  // Raw mode
  const rawEvents = ingest(raw);
  const rawProfile = classify(rawEvents);
  const noiseOk = rawProfile.noise.classification === spec.expectedNoise;
  const densityOk = rawProfile.density.classification === spec.expectedDensity;
  console.log(`${spec.name} (raw): Q3=${rawProfile.noise.classification} [${noiseOk?'OK':'FAIL'}], Q4=${rawProfile.density.classification} [${densityOk?'OK':'FAIL'}]`);

  // Anonymized mode
  const anonData = anonymize(raw, spec.seed);
  const anonEvents = ingest(anonData);
  const anonProfile = classify(anonEvents);
  const anonNoiseOk = anonProfile.noise.classification === spec.expectedNoise;
  const anonDensityOk = anonProfile.density.classification === spec.expectedDensity;
  console.log(`${spec.name} (anon): Q3=${anonProfile.noise.classification} [${anonNoiseOk?'OK':'FAIL'}], Q4=${anonProfile.density.classification} [${anonDensityOk?'OK':'FAIL'}]`);
}
EOF

