import { computeSpikes, computeLag1Autocorr, computeLinearTrendTStat, isSpikeDriven } from './src/classifier/noise.js';

// Test 1: spike detection
const baseline = new Array(25).fill(10);
const spikes = [200, 300, 400, 250, 350];
const values = [...baseline, ...spikes];
console.log('Spike test:');
console.log('values:', values.slice(0,5), '...', values.slice(-5));
const result = computeSpikes(values);
console.log('spike result:', result);

// Test 2: linear trend t-stat
const linear = Array.from({length:20}, (_,i) => i*10);
console.log('\nLinear trend test:');
console.log('values:', linear);
const t = computeLinearTrendTStat(linear);
console.log('t-stat:', t);

// Debug: check why t is 0
const n = linear.length;
const xMean = (n-1)/2;
const yMean = linear.reduce((a,b)=>a+b)/n;
let sxy=0, sxx=0;
for (let i=0; i<n; i++) {
  sxy += (i - xMean) * (linear[i] - yMean);
  sxx += (i - xMean)**2;
}
console.log('xMean:', xMean, 'yMean:', yMean, 'sxy:', sxy, 'sxx:', sxx);
const slope = sxy/sxx;
let sse=0;
for (let i=0; i<n; i++) {
  const pred = yMean + slope*(i-xMean);
  sse += (linear[i] - pred)**2;
}
console.log('slope:', slope, 'sse:', sse, 'mse:', sse/Math.max(1,n-2));

// Test 3: trending vs cyclical for linear ramp
const linear30 = Array.from({length:30}, (_,i) => i*10+100);
console.log('\nLinear ramp 30 values:');
const lag1 = computeLag1Autocorr(linear30);
const tStat = computeLinearTrendTStat(linear30);
const spikeDriven = isSpikeDriven(linear30);
console.log('lag1:', lag1, 't-stat:', tStat, 'isSpikeDriven:', spikeDriven);

// Test the spike detection mechanism for linear ramp
// Mean = 245, median = 245 -> mean/median = 1, so isSpikeDriven should be false
const mean = linear30.reduce((a,b)=>a+b)/linear30.length;
const sorted = [...linear30].sort((a,b)=>a-b);
const median = sorted[Math.floor(sorted.length/2)];
console.log('mean:', mean, 'median:', median, 'ratio:', mean/median);
EOF
","description":"Debug failing noise test assertions"}

