# Additional probes: path traversal in analyze(), constructor injection, immutability
node --input-type=module <<'EOF'
import { ForgeConstruct } from './src/index.js';
import { exportCertificate } from './src/rlmf/certificates.js';

// Probe 7: getCertificates() mutation safety
const forge = new ForgeConstruct();
const certs1 = forge.getCertificates();
certs1.push({ injected: true });
const certs2 = forge.getCertificates();
console.log('getCertificates() isolation:', certs2.length === 0);  // true — defensive copy

// Probe 8: exportCertificate does not mutate input theatre
const theatre = {
  template: 'threshold_gate',
  params: { threshold: 5.0 },
  status: 'resolved',
  created_at: 1000,
  position_probability: 0.8,
  position_history: [{ t: 1 }],
  resolution: { outcome: true, settled_at: 2000, settlement_class: 'oracle' },
};
const before = JSON.stringify(theatre);
exportCertificate(theatre, { theatre_id: 'x' });
const after = JSON.stringify(theatre);
console.log('exportCertificate does not mutate theatre:', before === after);

// Probe 9: position_history is not shared reference in cert (mutation safety)
const cert = exportCertificate(theatre);
cert.position_history.push({ injected: true });
console.log('position_history ref shared (expected: true — same ref):', theatre.position_history.length);
// Note: position_history is NOT copied — it's a reference to theatre.position_history

// Probe 10: prototype chain not polluted by lookup tables
import { computeUsefulness } from './src/filter/usefulness.js';
const obj = {};
console.log('Object prototype unpolluted:', obj.multi_tier === undefined);
EOF

